#
# find-mocks.sh — validate and manage counterfeiter-generated mock directories
#
# USAGE
#   find-mocks.sh [--delete] [ROOT]
#
# DESCRIPTION
#   Scans ROOT (default: current directory) for every directory that contains
#   at least one Go file declaring 'package mock'. For each such directory it
#   checks that *every* .go file carries the counterfeiter generation marker:
#
#       // Code generated by counterfeiter. DO NOT EDIT.
#
#   A directory passes (OK) when all files are counterfeiter output.
#   A directory fails (FAIL) when any file was written by hand.
#
# OPTIONS
#   --delete   After a passing check, delete the directory. Use this before
#              running 'go generate ./...' to do a clean regeneration:
#
#                  ./scripts/find-mocks.sh --delete
#                  go generate ./...
#
#              Directories that contain hand-written files are NOT deleted so
#              that no work is lost.
#
# EXIT STATUS
#   0   All mock directories passed (or no mock directories found).
#   1   At least one mock directory contains a non-counterfeiter file.
#
# BACKGROUND
#   In FSC, mock/ directories are owned exclusively by counterfeiter. They must
#   never contain handwritten code. Handwritten test doubles belong in fake/ or
#   fakes/ directories instead. See docs/dev/mocks.md for the full convention.
set -euo pipefail

DELETE=false
ROOT="."
for arg in "$@"; do
    case "$arg" in
        --delete) DELETE=true ;;
        *) ROOT="$arg" ;;
    esac
done

COUNTERFEITER_MARKER="// Code generated by counterfeiter. DO NOT EDIT."

exit_code=0

while IFS= read -r dir; do
    violations=()
    while IFS= read -r file; do
        if ! grep -qF "$COUNTERFEITER_MARKER" "$file"; then
            violations+=("$file")
        fi
    done < <(find "$dir" -maxdepth 1 -name "*.go")

    if [[ ${#violations[@]} -gt 0 ]]; then
        echo "FAIL $dir"
        for v in "${violations[@]}"; do
            echo "     not counterfeiter: $v"
        done
        exit_code=1
    else
        echo "OK   $dir"
        if [[ "$DELETE" == true ]]; then
            rm -rf "$dir"
            echo "     deleted"
        fi
    fi
done < <(
    find "$ROOT" -type f -name "*.go" \
        | xargs grep -l "^package mock" 2>/dev/null \
        | sed 's|/[^/]*$||' \
        | sort -u
)

exit "$exit_code"
